return items.map(item => {
const email = (item.json.email || '').trim().toLowerCase();

const email_valid =
/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email) &&
!email.includes('..');

return {
json:{
...item.json,
email,
email_valid
}
};
});

return items.map(item => {

let phone = (item.json.phone || '')
.toString()
.replace(/\D/g,'');

let country='unknown';

if(phone.length===10){
phone='91'+phone;
country='IN';
}
else if(phone.startsWith('1')) country='US';
else if(phone.startsWith('44')) country='UK';
else if(phone.startsWith('971')) country='UAE';
else if(phone.startsWith('49')) country='DE';
else if(phone.startsWith('61')) country='AU';

if(phone.length < 10 || phone.length > 15){
phone='';
}

return {
json:{
...item.json,
phone_standardized: phone,
country
}
};
});

const seen = {};

return items.map(item => {

const email = item.json.email;
const phone = item.json.phone_standardized;

const key = email + "|" + phone;

let is_duplicate = false;

if(seen[key]){
is_duplicate = true;
}else{
seen[key] = true;
}

return {
json:{
...item.json,
is_duplicate
}
};

});

return items.map(item => {

let company = item.json.company;

if(!company || company.trim()===''){

const email = item.json.email || '';

if(email.includes('@')){
company = email.split('@')[1].split('.')[0];
company =
company.charAt(0).toUpperCase() +
company.slice(1);
}else{
company='Unknown Company';
}

}

return {
json:{
...item.json,
company_enriched: company
}
};

});

return items.map(item => {

const flags=[];

if(!item.json.email_valid)
flags.push('Invalid Email');

if(!item.json.phone_standardized)
flags.push('Invalid Phone');

if(item.json.is_duplicate)
flags.push('Duplicate');

if(!item.json.company || item.json.company==='')
flags.push('Missing Company');

return {
json:{
...item.json,
data_quality_flags: flags,
quality_score: 100 - (flags.length * 25)
}
};

});

let total = items.length;

let summary = {
  total_records: total,
  valid_records: 0,
  invalid_email: 0,
  invalid_phone: 0,
  duplicates: 0,
  missing_company: 0
};

let report = [];

for (const item of items) {
  const d = item.json;

  let isValid = true;

  // Email validation
  if (!d.email_valid) {
    summary.invalid_email++;
    isValid = false;
  }

  // Phone validation
  if (!d.phone_standardized) {
    summary.invalid_phone++;
    isValid = false;
  }

  // Duplicate check
  if (d.is_duplicate) {
    summary.duplicates++;
    isValid = false;
  }

  // Company check
  if (!d.company || d.company === '' || d.company === null) {
    summary.missing_company++;
    isValid = false;
  }

  if (isValid) {
    summary.valid_records++;
  }

  report.push({
    id: d.id,
    name: d.name,
    email: d.email,
    country: d.country || 'unknown',
    status: isValid ? 'VALID' : 'INVALID',
    flags: d.data_quality_flags || []
  });
}

return [
  {
    json: {
      summary,
      report
    }
  }
];
